#!/bin/bash
cd "/home/ubuntu/Alpha monitor"

echo '' | base64 -d > data_fetch/lof_iopv/fetcher.py
echo '' | base64 -d > strategy/lof_iopv/service.py
echo '' | base64 -d > runtime_data/backtest/a_results.json
echo '' | base64 -d > ui/src/components/LofCardList.jsx
echo '' | base64 -d > ui/dist/index.html
echo '' | base64 -d > 'ui/dist/assets/index-B_eJW4wM.js'

python3 -c "compile(open('data_fetch/lof_iopv/fetcher.py',encoding='utf-8').read(),'f','exec'); print('fetcher OK')"
python3 -c "compile(open('strategy/lof_iopv/service.py',encoding='utf-8').read(),'f','exec'); print('service OK')"

sudo systemctl restart alpha-monitor
sleep 5
curl -s http://127.0.0.1:5001/api/market/lof-arbitrage | python3 -c "
import sys,json
d=json.load(sys.stdin)
rows=d.get('data',{}).get('rows',[])
print(f'rows: {len(rows)}')
codes=[r.get('code') for r in rows]
print(f'codes: {sorted(codes)}')
r=rows[0] if rows else {}
print(f'calcTarget: {r.get(\"calcTarget\")}')
print(f'r2: {r.get(\"r2\")}')
has_old=any(c in codes for c in ['159202','513660','513690','520600'])
print(f'has_old_funds: {has_old}')
"